exercises.solution_code:
#include <cmath>
#include <iomanip>
#include <iostream>

int main() {
    int base, exp;
    std::cin >> base >> exp;

    double double_result = std::pow(base, exp);
    int int_result = static_cast<int>(std::pow(base, exp) + 0.5);

    std::cout << "double_result: "
              << std::fixed << std::setprecision(1)
              << double_result << '\n';
    std::cout << "int_result: " << int_result << '\n';
    std::cout << "manual_check: " << int_result << '\n';

    return 0;
}

