exercises.solution_code:
#include <iostream>

int main() {
    int a, b, c;
    std::cin >> a >> b >> c;

    int rem_ab = a % b;
    int rem_ac = a % c;

    std::cout << "a % b: " << rem_ab << '\n';
    std::cout << "a % c: " << rem_ac << '\n';

    if (rem_ab > 0)
        std::cout << "sign_ab: positive\n";
    else if (rem_ab < 0)
        std::cout << "sign_ab: negative\n";
    else
        std::cout << "sign_ab: zero\n";

    if (rem_ac > 0)
        std::cout << "sign_ac: positive\n";
    else if (rem_ac < 0)
        std::cout << "sign_ac: negative\n";
    else
        std::cout << "sign_ac: zero\n";

    return 0;
}
